    function showOnboarding() { let dialog = $("v9OnboardingDialog"); if (!dialog) { dialog = document.createElement("dialog"); dialog.id = "v9OnboardingDialog"; dialog.innerHTML = `<form method="dialog" class="dialog-card onboarding"><h2>Hybrid Tile Studio v9</h2><ol><li>Open an RPG Maker MZ project and run the Compatibility Lab.</li><li>Edit through authoring layers; use Atomic Save All when ready.</li><li>Capture reusable prefabs from selections and link instances.</li><li>Use the generator workbench with masks, previews, and diagnostics.</li><li>Commit canonical .hybrid data through the desktop Git workspace.</li></ol><p>Backups and recovery are safety nets, not replacements for source control.</p><div class="dialog-actions"><button value="ok" class="primary">Start mapping</button></div></form>`; document.body.append(dialog); } dialog.showModal(); }
